RealSense D415, SDK version 2.1.3, MacOS 10.13.3

I have modified the opencv samples imshow and grabcut in order to show the colorized depth and rgb frames in two opencv windows as shown in the code below. 

However, even with this very simple structure, the stream is quite jerky as if there were frequent frame drops. 

Moreover, if I remove the guard if(!depth) continue; then the program crashes as it receives null depth frames, while I thought this issue was fixed in a previous release.

I also tried to add a queue to the code, but the stream is still jerky. I was not expecting the stream to be this jerky even with no processing involved, am I doing anything wrong?


```
#include <librealsense2/rs.hpp> // Include RealSense Cross Platform API
#include <opencv2/opencv.hpp>   // Include OpenCV API

using namespace rs2;
using namespace cv;

cv::Mat frame_to_mat(const rs2::frame& f)
{
    using namespace cv;
    using namespace rs2;
    
    auto vf = f.as<video_frame>();
    const int w = vf.get_width();
    const int h = vf.get_height();
    
    if (f.get_profile().format() == RS2_FORMAT_BGR8)
    {
        return Mat(Size(w, h), CV_8UC3, (void*)f.get_data(), Mat::AUTO_STEP);
    }
    else if (f.get_profile().format() == RS2_FORMAT_RGB8)
    {
        auto r = Mat(Size(w, h), CV_8UC3, (void*)f.get_data(), Mat::AUTO_STEP);
        cv::cvtColor(r, r, CV_BGR2RGB);
        return r;
    }
    else if (f.get_profile().format() == RS2_FORMAT_Z16)
    {
        return Mat(Size(w, h), CV_16UC1, (void*)f.get_data(), Mat::AUTO_STEP);
    }
    else if (f.get_profile().format() == RS2_FORMAT_Y8)
    {
        return Mat(Size(w, h), CV_8UC1, (void*)f.get_data(), Mat::AUTO_STEP);;
    }
    
    throw std::runtime_error("Frame format is not supported yet!");
}

